class Solution:
    def findWords(self, board, words):
        m, n = len(board), len(board[0])
        def dfs(i, j, k, word, visited):
            if k == len(word):
                return True
            if i < 0 or i >= m or j < 0 or j >= n:
                return False
            if (i, j) in visited or board[i][j] != word[k]:
                return False
            visited.add((i, j))
            found = (dfs(i+1,j,k+1,word,visited) or dfs(i-1,j,k+1,word,visited) or
                     dfs(i,j+1,k+1,word,visited) or dfs(i,j-1,k+1,word,visited))
            visited.discard((i, j))
            return found
        result = []
        for word in words:
            for i in range(m):
                for j in range(n):
                    if dfs(i, j, 0, word, set()):
                        result.append(word)
                        break
                else:
                    continue
                break
        return sorted(result)

