class Solution:
    def findWords(self, board, words):
        TRIE_END = '#'
        trie = {}
        for w in words:
            node = trie
            for c in w:
                node = node.setdefault(c, {})
            node[TRIE_END] = w
        m, n = len(board), len(board[0])
        result = []
        def dfs(i, j, node):
            c = board[i][j]
            if c not in node:
                return
            nxt = node[c]
            if TRIE_END in nxt:
                result.append(nxt[TRIE_END])
                del nxt[TRIE_END]
            board[i][j] = '#'
            for di, dj in ((1,0),(-1,0),(0,1),(0,-1)):
                ni, nj = i+di, j+dj
                if 0 <= ni < m and 0 <= nj < n and board[ni][nj] != '#':
                    dfs(ni, nj, nxt)
            board[i][j] = c
        for i in range(m):
            for j in range(n):
                dfs(i, j, trie)
        return sorted(result)

