var findWords = function(board, words) {
    const TRIE_END = '#';
    const trie = {};
    for (const w of words) {
        let node = trie;
        for (const c of w) {
            if (!node[c]) node[c] = {};
            node = node[c];
        }
        node[TRIE_END] = w;
    }
    const m = board.length, n = board[0].length;
    const result = [];
    const dfs = (i, j, node) => {
        const c = board[i][j];
        if (!node[c]) return;
        const nxt = node[c];
        if (nxt[TRIE_END]) {
            result.push(nxt[TRIE_END]);
            delete nxt[TRIE_END];
        }
        board[i][j] = '#';
        for (const [di, dj] of [[1,0],[-1,0],[0,1],[0,-1]]) {
            const ni = i + di, nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n && board[ni][nj] !== '#') {
                dfs(ni, nj, nxt);
            }
        }
        board[i][j] = c;
    };
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            dfs(i, j, trie);
        }
    }
    return result.sort();
};
